// Extract message from OpenWebUI webhook payload
// Payload: { messages: [{role, content}], user: {email, name} }
const body = $('Webhook Trigger').first().json.body;
const messages = body.messages || [];
const lastUserMsg = messages.filter(m => m.role === 'user').pop();
const userMessage = lastUserMsg?.content || '';
const userEmail = body.user?.email || '';
const userName = body.user?.name || 'Unknown';

return [{
  json: {
    userMessage,
    userEmail,
    userName
  }
}];

const soul = $('Load Soul').all().map(i => i.json);
const agentsRaw = $('Load Agents Config').all().map(i => i.json);
const agents = [...new Map(agentsRaw.map(a => [a.key, a])).values()];
const user = $('Load User Profile').first()?.json || {};
const userRole = $('Load User Role').first()?.json || {};
const role = userRole.role || 'readonly';
const roleName = userRole.name || '';
const historyRaw = $('Load Conversation History').all().map(i => i.json);
const seenHist = new Set();
const history = historyRaw.filter(h => { const k = h.role + ':' + h.content; if (seenHist.has(k)) return false; seenHist.add(k); return true; });
const userMessage = $('Normalize Message').first().json.userMessage || '';
const userEmail = $('Normalize Message').first().json.userEmail || 'unknown';
const userName = $('Normalize Message').first().json.userName || 'Unknown';

const baseUrl = '{{SUPABASE_URL}}';
const serviceKey = '{{SUPABASE_SERVICE_KEY}}';
const dbHeaders = { 'apikey': serviceKey, 'Authorization': 'Bearer ' + serviceKey, 'Content-Type': 'application/json' };
let notifications = [];
try {
  notifications = await helpers.httpRequest({ method: 'GET', url: baseUrl + '/rest/v1/notifications?read=eq.false&or=(recipient_email.eq.' + encodeURIComponent(userEmail) + ',recipient_email.eq.all)&order=created_at.desc&limit=10', headers: dbHeaders });
  if (notifications && notifications.length > 0) {
    const ids = notifications.map(n => n.id);
    await helpers.httpRequest({ method: 'PATCH', url: baseUrl + '/rest/v1/notifications?id=in.(' + ids.join(',') + ')', headers: { ...dbHeaders, 'Prefer': 'return=minimal' }, body: JSON.stringify({ read: true }) });
  }
} catch(e) {}

const soulText = soul.map(s => '## ' + s.key + '\n' + s.content).join('\n\n');
const agentText = agents.map(a => '## ' + a.key + '\n' + a.content).join('\n\n');
const userText = user.display_name ? 'Name: ' + user.display_name + ' (' + user.name + ')\nTimezone: ' + user.timezone + '\nKontext: ' + user.context + '\nPrefs: ' + JSON.stringify(user.preferences) + '\nSetup done: ' + (user.setup_done !== false ? 'true' : 'false') : 'Unbekannter User';

const roleContextMap = { marketing: 'Rolle: Marketing (' + roleName + ')\nDu hilfst bei Social Media, Content-Erstellung und Posting.\nBevorzugte Tools: create_instagram_post, schedule_post, alpine_weather\nNutze Bewertungs-Tools nur wenn explizit danach gefragt wird.', member_relations: 'Rolle: Mitgliederbetreuung (' + roleName + ')\nDu hilfst bei Bewertungen, Mitgliedsbetrieben und deren Anliegen.\nBevorzugte Tools: query_reviews, review_summary, alpine_weather\nNutze Posting-Tools nur wenn explizit danach gefragt wird.', admin: 'Rolle: Admin (' + roleName + ')\nVollzugriff auf alle Tools und Funktionen.', readonly: 'Rolle: Lesezugriff\nDu kannst Informationen abrufen, aber keine Aktionen ausfuehren.' };
const roleContext = roleContextMap[role] || roleContextMap.readonly;

const historyText = history.reverse().map(h => h.role + ': ' + h.content).join('\n');

let notifText = '';
if (notifications && notifications.length > 0) {
  notifText = '\n\n# UNGELESENE BENACHRICHTIGUNGEN\nWICHTIG: Erwaehne diese Benachrichtigungen proaktiv am Anfang deiner Antwort!\n';
  for (const n of notifications) { notifText += '- [' + n.type + '] ' + n.title + ': ' + (n.body || '') + '\n'; }
}

const now = $now.setZone(user.timezone || 'UTC').toFormat('cccc, dd LLLL yyyy, HH:mm');

const systemPrompt = '# CURRENT TIME\n' + now + '\n\n# SOUL\n' + soulText + '\n\n# AGENT CONFIG\n' + agentText + '\n\n# USER ROLE\n' + roleContext + '\n\n# USER PROFILE\n' + userText + notifText + '\n\n# RECENT CONVERSATION\n' + historyText;

return [{ json: { systemPrompt, userMessage, userEmail, userName, userId: userEmail, sessionId: 'oi:' + userEmail } }];

// Save conversation to Supabase
const userMessage = $('Build System Prompt').first().json.userMessage;
const assistantMessage = $('AI Agent').first().json.output;
const sessionId = $('Build System Prompt').first().json.sessionId;
const userId = $('Build System Prompt').first().json.userId;

// Mark onboarding as done after first response
const setupDone = $('Load User Profile').first()?.json?.setup_done;
const markSetupDone = setupDone === false;

return [{
  json: {
    userMessage,
    assistantMessage,
    sessionId,
    userId,
    markSetupDone
  }
}];

