// Debug: figure out what query actually is
const qType = typeof query;
let mcpUrl = '', toolName = '', args = {};

if (qType === 'object' && query !== null) {
  // query is already an object
  mcpUrl = query.mcp_url || '';
  toolName = query.tool_name || '';
  args = query.arguments || {};
} else if (qType === 'string') {
  try {
    const parsed = JSON.parse(query);
    mcpUrl = parsed.mcp_url || '';
    toolName = parsed.tool_name || '';
    args = parsed.arguments || {};
  } catch(e) {
    return 'Parse error: query=' + String(query).substring(0,200) + ' type=' + qType;
  }
} else {
